class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        if (!head) return NULL;
        ListNode* dummy = new ListNode(0);
        dummy->val = 0;dummy->next = head;
        ListNode* p1 = head, p2 = head->next;
        while(p2)
        {
            p2 = p2->next;
            dummy->next = p1->next;
            p1->next = p2;
        }
        return dummy->next;
    }
};

int main() {
    Solution sol; 
    int t;
    cin >> t;
    while(t--){
        int n;
        cin >> n;
        ListNode* head = new ListNode(0);
        head->next = NULL;
        for (int i=0;i<n;i++)
        {
            int val;
            cin >> val;
            ListNode* node = new ListNode(val);
            node->next = head->next;
            head->next = node;
        }
        printList(sol.reverseList(head->next));
    }
    return 0;
}
void printList(ListNode* node){
    while(node){
        cout << node->val << " ";
        node = node->next;
    }
    cout << "\n";
}
